//frontend/src/app/features/auth/login/login.ts 
import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MaterialModule } from '../../../shared/material.module'; // Importamos tus botones y cards
import { ReactiveFormsModule } from '@angular/forms';

@Component({
  selector: 'app-login',
  standalone: true, // ¡Vital para Angular 17!
  imports: [CommonModule, MaterialModule, ReactiveFormsModule],
  templateUrl: './login.html',
  styleUrl: './login.css',
})
export class LoginComponent { } // Le ponemos el nombre completo
